ALTER TABLE "absensi"
  ADD PRIMARY KEY ("id"),
  ADD KEY "nik" ("nik");

ALTER TABLE "karyawan"
  ADD PRIMARY KEY ("id"),
  ADD UNIQUE KEY "nik" ("nik"),
  ADD UNIQUE KEY "email" ("email");

ALTER TABLE "absensi"
  MODIFY "id" SERIAL NOT NULL, ;

ALTER TABLE "karyawan"
  MODIFY "id" SERIAL NOT NULL, ;

ALTER TABLE "absensi"
  ADD CONSTRAINT "fk_karyawan_absen" FOREIGN KEY ("nik") REFERENCES "karyawan" ("nik") ON DELETE CASCADE ON UPDATE CASCADE;
